// Solution
#include <iostream>
#include <vector>
using namespace std;
class Solution {
public:
    int findFirstDuplicate(vector<int>& nums) {
        for (int i = 0; i < nums.size(); i++) {
            for (int j = i + 1; j < nums.size(); j++) {
                if (nums[i] == nums[j]) {
                    return nums[i];
                }
            }
        }
        return -1;
    }
};
int main() {
    Solution solution;
    vector<int> nums = {1, 2, 3, 4, 5, 2};
    cout << solution.findFirstDuplicate(nums) << endl;
    return 0;
}

